from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
import re

app = Flask(__name__)

# Configure logging
handler = RotatingFileHandler('app.log', maxBytes=10000, backupCount=1)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
app.logger.addHandler(handler)
app.logger.setLevel(logging.INFO)

def sanitize_data(data):
    # Remove sensitive information
    data = re.sub(r'("password":\s*")[^"]*"', r'\1***"', data)
    data = re.sub(r'("token":\s*")[^"]*"', r'\1***"', data)
    return data

@app.before_request
def log_request_info():
    headers = dict(request.headers)
    headers.pop('Authorization', None)  # Remove sensitive headers
    body_data = request.get_data(as_text=True)
    sanitized_body_data = sanitize_data(body_data)
    app.logger.info(f'Request Headers: {headers}')
    app.logger.info(f'Request Body: {sanitized_body_data}')

@app.after_request
def log_response_info(response):
    response_data = response.get_data(as_text=True)
    sanitized_response_data = sanitize_data(response_data)
    app.logger.info(f'Response Status: {response.status}')
    app.logger.info(f'Response Body: {sanitized_response_data}')
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    app.logger.error(f'Error: {str(e)}')
    return jsonify(error=str(e)), 500

